import numpy as np

def build_coulomb(eri, P):
    """Build Coulomb matrix: Jμν = Σλσ Pλσ(μν|λσ)."""
    n = P.shape[0]
    J = np.zeros((n, n))
    for mu in range(n):
        for nu in range(n):
            for lam in range(n):
                for sig in range(n):
                    J[mu, nu] += P[lam, sig] * eri[mu, nu, lam, sig]
    return J

def build_exchange(eri, P):
    """Build Exchange matrix: Kμν = Σλσ Pλσ(μσ|λν)."""
    n = P.shape[0]
    K = np.zeros((n, n))
    for mu in range(n):
        for nu in range(n):
            for lam in range(n):
                for sig in range(n):
                    K[mu, nu] += P[lam, sig] * eri[mu, sig, lam, nu]
    return K

# Test
n = 3
np.random.seed(0)
eri = np.random.randn(n, n, n, n)
P = np.eye(n)

J = build_coulomb(eri, P)
K = build_exchange(eri, P)
print(f"J matrix:\n{J}")
print(f"K matrix:\n{K}")
